/**
 * @summary Get a single call
 */
export const getGetCallUrl = (id: number) => {
  return `/api/calls/${id}`;
};

export const getCall = async (
  id: number,
  options?: RequestInit,
): Promise<Call> => {
  return customFetch<Call>(getGetCallUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetCallQueryKey = (id: number) => {
  return [`/api/calls/${id}`] as const;
};

export const getGetCallQueryOptions = <
  TData = Awaited<ReturnType<typeof getCall>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getCall>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetCallQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getCall>>> = ({
    signal,
  }) => getCall(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getCall>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetCallQueryResult = NonNullable<
  Awaited<ReturnType<typeof getCall>>
>;
export type GetCallQueryError = ErrorType<unknown>;

/**
 * @summary Get a single call
 */

export function useGetCall<
  TData = Awaited<ReturnType<typeof getCall>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getCall>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetCallQueryOptions(id, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Update agent status
 */
export const getUpdateAgentStatusUrl = () => {
  return `/api/agent/status`;
};

export const updateAgentStatus = async (
  updateAgentStatusBody: UpdateAgentStatusBody,
  options?: RequestInit,
): Promise<AgentStatusResponse> => {
  return customFetch<AgentStatusResponse>(getUpdateAgentStatusUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(updateAgentStatusBody),
  });
};

export const getUpdateAgentStatusMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateAgentStatus>>,
    TError,
    { data: BodyType<UpdateAgentStatusBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateAgentStatus>>,
  TError,
  { data: BodyType<UpdateAgentStatusBody> },
  TContext
> => {
  const mutationKey = ["updateAgentStatus"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateAgentStatus>>,
    { data: BodyType<UpdateAgentStatusBody> }
  > = (props) => {
    const { data } = props ?? {};

    return updateAgentStatus(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateAgentStatusMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateAgentStatus>>
>;
export type UpdateAgentStatusMutationBody = BodyType<UpdateAgentStatusBody>;
export type UpdateAgentStatusMutationError = ErrorType<unknown>;

